INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Broken link and redirect detection$q$, $q$Identifies 4xx and 5xx errors, redirect chains, and redirect loops across an entire crawled site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Custom extraction$q$, $q$Pulls specific page data using XPath, CSS Path, or regex to scrape structured content during a crawl.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$JavaScript rendering$q$, $q$Crawls JavaScript-heavy sites and single-page apps by rendering pages before analysis.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Third-party integrations$q$, $q$Connects to Google Analytics, Search Console, and PageSpeed Insights to combine crawl and performance data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Visualizations$q$, $q$Generates crawl diagrams and directory tree maps to visualize site structure and internal linking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Duplicate content auditing$q$, $q$Flags duplicate titles, meta descriptions, and near-duplicate page content across the site.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$XML sitemap generation$q$, $q$Builds XML sitemaps directly from crawl data for submission to search engines.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Scheduling and automation$q$, $q$Runs crawls on a schedule and supports command-line operation for automated workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Extremely detailed crawl data and granular control over crawl settings$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Flat annual per-seat fee rather than consumption-based pricing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Runs locally, keeping crawl data off third-party servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Industry-standard tool with extensive documentation and community knowledge$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Highly configurable to mimic different bots and rendering modes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Desktop-only, with no native cloud or SaaS dashboard$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Steep learning curve for SEO beginners$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Can be memory-intensive on very large crawls without database storage mode$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Free version limited to 500 URLs per crawl$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$No built-in rank tracking or backlink index, requiring separate tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Is Screaming Frog SEO Spider free?$q$, $q$Yes, a free version is available that crawls up to 500 URLs with most core features. Crawling beyond that limit requires a paid license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$How much does a Screaming Frog license cost?$q$, $q$A single license costs 199 GBP per year (about 279 USD), billed annually per user, with volume discounts for 5 or more licenses.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Does Screaming Frog work on Mac and Linux?$q$, $q$Yes, it runs natively on Windows, macOS, and Ubuntu.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Can Screaming Frog crawl JavaScript websites?$q$, $q$Yes, the paid version supports JavaScript rendering to crawl single-page applications and dynamically loaded content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Does Screaming Frog integrate with Google Analytics and Search Console?$q$, $q$Yes, both integrations are available in the paid version, letting users combine crawl data with traffic and search performance metrics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Is Screaming Frog a cloud-based tool?$q$, $q$No, it is a locally installed desktop application; crawl data stays on the user's machine unless manually exported.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Does Screaming Frog offer log file analysis?$q$, $q$Log file analysis is handled by a separate companion product, the Screaming Frog Log File Analyser, sold independently.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Are licenses shared across multiple users?$q$, $q$No, licenses are sold per user; each additional user requires its own license, though volume discounts apply.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Technical SEO audits$q$, $q$Consultants and agencies use the SEO Spider to identify broken links, redirect issues, duplicate content, and metadata problems across client websites.$q$, $q$SEO consultants and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Site migration quality assurance$q$, $q$Teams crawl staging and live sites before and after a migration to compare URL structures, redirects, and indexability.$q$, $q$In-house SEO and web teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Ongoing site health monitoring$q$, $q$Scheduled crawls track new technical issues over time as sites are updated, feeding into regular SEO reporting.$q$, $q$Enterprise SEO teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Free$q$, $q$0$q$, $q$free$q$, NULL, $q$["Crawl up to 500 URLs","Most core crawl and audit features","No JavaScript rendering or API integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Paid License (1-4 licenses)$q$, $q$199 GBP per year$q$, $q$annual$q$, NULL, $q$["Unlimited URL crawling, subject to memory and storage","JavaScript rendering","Google Analytics and Search Console integration","Custom extraction, scheduling, and API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$Paid License (20+ licenses)$q$, $q$169 GBP per year per license$q$, $q$annual$q$, NULL, $q$["All paid features included","Volume discount of roughly 15 percent per license"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Screaming Frog SEO Spider is a Windows, macOS, and Ubuntu desktop application that crawls websites like a search engine bot to uncover technical SEO problems. Built by the UK agency Screaming Frog, founded in 2010, it has become one of the most widely used tools in the SEO industry for site audits and migrations.$q$, $q$The tool is locally installed rather than cloud-based, meaning crawl data is stored on the user's own machine unless exported, which many agencies value for handling client data privately.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The SEO Spider surfaces broken links, redirect chains, duplicate titles and meta descriptions, missing alt text, malformed structured data, and orphaned pages. It supports JavaScript rendering for crawling modern web apps, custom extraction using XPath, CSS Path, or regular expressions, and integrates directly with Google Analytics, Google Search Console, and the PageSpeed Insights API to pull performance and traffic data into the same crawl report.$q$, $q$Additional capabilities include crawl and directory-tree visualizations, XML sitemap generation, scheduled crawling, and a command-line interface for automation, making it suitable for both one-off audits and recurring monitoring.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d3a5907-52ea-4312-8ed3-6325f131fbef', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The free version crawls up to 500 URLs and includes most core features. The paid license costs 199 GBP per year per user and removes the crawl limit, subject to available memory and disk space, while unlocking JavaScript rendering, API integrations, and scheduling. Volume discounts apply starting at 5 licenses and scale up to 20 or more licenses purchased together.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Browser-based WebRTC screen sharing$q$, $q$Viewers join through a link and watch in-browser with no software installation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Built-in TURN server$q$, $q$Includes an integrated TURN server for NAT traversal, simplifying self-hosted deployment behind firewalls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$End-to-end encrypted streams$q$, $q$WebRTC's DTLS/SRTP requirements mean the server only relays encrypted media it cannot decrypt.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Single binary or Docker deployment$q$, $q$Deploys as one compiled binary or an official Docker image, runnable in minutes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Multi-viewer rooms$q$, $q$Supports multiple simultaneous viewers per screen-share session via shareable room codes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Low-latency streaming$q$, $q$Peer-to-peer WebRTC connections minimize delay compared to relayed video conferencing tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Open-source GPL-3.0 license$q$, $q$Fully open source, self-hostable, and free to modify or audit.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Cross-platform browser support$q$, $q$Works across desktop and mobile browsers without dedicated native apps.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Full data control through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$No client software installation required for viewers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Low latency thanks to peer-to-peer WebRTC$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Built-in TURN server simplifies deployment$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Lightweight and focused on a single purpose$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Requires self-hosting know-how such as server, domain, and TLS setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$No official commercial support or SLA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Lacks recording, chat, or whiteboard features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$No hosted or managed version offered by the project itself$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Limited to screen sharing rather than a full conferencing suite$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Is Screego really free?$q$, $q$Yes, Screego is free and open source under the GPL-3.0 license; the only cost is the infrastructure you self-host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Do viewers need to install anything to watch a Screego share?$q$, $q$No, viewers join through a browser link and watch entirely in-browser using WebRTC, with no app installation required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Can Screego be used without self-hosting?$q$, $q$There is a public demo instance at app.screego.net for trying it, but production use is intended to be self-hosted on your own server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Is Screego secure?$q$, $q$Media streams are encrypted end to end via WebRTC's DTLS/SRTP protocols, and the Screego server only relays encrypted packets without being able to view the content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Does Screego support recording sessions?$q$, $q$No, Screego is focused solely on live screen sharing and does not include built-in recording, chat, or whiteboard features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$How is Screego deployed?$q$, $q$It can be deployed as a single compiled binary or via the official Docker image, typically running within a couple of minutes.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$What license does Screego use?$q$, $q$Screego is released under the GNU General Public License version 3.0 (GPL-3.0).$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Who maintains Screego?$q$, $q$Screego is an open-source community project hosted on GitHub at screego/server, maintained by volunteer contributors rather than a company.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Remote pair programming and code review$q$, $q$Developers share their screen directly in-browser for live coding sessions without routing through a corporate video tool.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Privacy-conscious internal screen sharing$q$, $q$Organizations that want full control over data and infrastructure self-host Screego instead of using third-party SaaS conferencing tools.$q$, $q$Security and privacy-focused organizations, self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Lightweight team screen-share rooms$q$, $q$Distributed teams stand up a persistent internal Screego instance for quick ad hoc screen-sharing without scheduling a full meeting.$q$, $q$Distributed and remote engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$Self-Hosted$q$, $q$0$q$, $q$free, self-hosted$q$, NULL, $q$["Unlimited use once self-hosted","Full source code access under GPL-3.0","Community support via GitHub","Docker or single-binary deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Screego is an open-source, self-hosted screen-sharing tool aimed at developers who want a lightweight, low-latency alternative to bundled screen sharing in tools like Zoom or Teams. It runs in the browser using WebRTC and requires no client installation for viewers.$q$, $q$Because it is community-maintained under the GPL-3.0 license rather than sold by a company, Screego has no pricing tiers, sales contact, or commercial support plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Screego provides browser-based screen sharing with an integrated TURN server for NAT traversal, so self-hosters do not need to configure separate relay infrastructure. All media streams are encrypted end to end via WebRTC's DTLS/SRTP requirements, and the server cannot view shared screen content.$q$, $q$The tool supports multiple simultaneous viewers per room, short shareable room codes, and deployment via a single binary or Docker image, making it fast to stand up on a home server, VPS, or internal company infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Screego itself is entirely free and open source under the GPL-3.0 license. The only cost is whatever infrastructure the user chooses to self-host it on, such as a small VPS or existing home server; there are no subscription tiers, seat licenses, or paid upgrades from the project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eac79351-70e4-48de-8016-9c64aff91049', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Automatic cursor-aware zoom and pan$q$, $q$Zooms and pans the recording automatically based on cursor movement and clicks, no manual keyframing needed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Smooth cursor effects$q$, $q$Highlights and smooths cursor movement and click animations for a polished presentation feel.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Customizable backgrounds and shadows$q$, $q$Adds gradient or image backgrounds, inset spacing, and shadows around the recorded window.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Webcam, mic, and system audio capture$q$, $q$Records screen, webcam, microphone, and system audio simultaneously.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$iOS device recording$q$, $q$Captures iOS device screens over a USB connection for mobile app demos.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Audio enhancement$q$, $q$Applies background noise removal and voice-level normalization automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Local transcript generation$q$, $q$Generates video transcripts processed locally on the user's Mac.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$High-quality export options$q$, $q$Exports up to 4K at 60fps, animated GIF, or a shareable hosted link.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Produces polished demo videos with minimal manual editing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Simple, focused workflow purpose-built for product demos$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$High-quality 4K export and shareable link hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Used internally by well-known tech companies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Frequent promotions and a student discount lower the entry cost$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$macOS only, no Windows or Linux version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$No free export, a subscription is required to save finished videos$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Lifetime license is no longer available to new customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Lacks a full multi-track editing timeline found in ScreenFlow$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Subscription cost can add up compared to one-time-purchase competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Is Screen Studio free?$q$, $q$You can download Screen Studio and record and edit videos for free, but exporting a finished video requires an active paid subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$How much does Screen Studio cost?$q$, $q$The annual plan works out to roughly 9 USD per month (108 USD per year), while monthly billing has historically run between about 20 and 29 USD per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Can I still buy a lifetime license?$q$, $q$No, the one-time 229 USD lifetime license has been discontinued for new customers, though existing lifetime license holders keep their access.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Does Screen Studio work on Windows?$q$, $q$No, Screen Studio is macOS only, requiring roughly macOS Ventura 13.1 or later.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Who built Screen Studio?$q$, $q$Screen Studio was created by Polish developer Adam Pietrasiak along with co-founders Maciej and David, launching in late 2022 as a bootstrapped, indie-built product.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Does Screen Studio support webcam recording?$q$, $q$Yes, it can record webcam, microphone, and system audio simultaneously alongside the screen capture.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Is there a student discount?$q$, $q$Yes, Screen Studio has offered a discount for students and educators with a verified academic email address.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$What is the maximum export quality?$q$, $q$Screen Studio supports exporting video up to 4K resolution at 60 frames per second.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Product demo videos for SaaS marketing$q$, $q$Marketing and growth teams record polished product walkthroughs without needing a dedicated video editor.$q$, $q$Product marketers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Tutorial and onboarding content creation$q$, $q$Educators and customer success teams create clear, professional-looking how-to videos quickly.$q$, $q$Educators, developer relations, and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Social media and short-form demo clips$q$, $q$Indie founders and creators produce polished short clips for launches and social promotion.$q$, $q$Indie founders and content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Monthly$q$, $q$20 to 29 USD per month$q$, $q$monthly$q$, NULL, $q$["Full feature access","4K 60fps export","Shareable links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Annual$q$, $q$108 USD per year (about 9 USD per month)$q$, $q$annual$q$, NULL, $q$["Full feature access at a discounted rate","4K 60fps export","Shareable links"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$Lifetime (legacy, no longer sold)$q$, $q$229 USD one-time$q$, $q$one-time$q$, NULL, $q$["Included 1 year of feature updates","Additional years of new features cost extra"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Screen Studio is a macOS screen recording app, launched in late 2022 by a small bootstrapped team led by Adam Pietrasiak in Krakow, Poland, built around the idea of automating the polish that used to require manual video editing.$q$, $q$It has become popular for product demos and tutorials thanks to automatic cursor-aware zoom and smooth animations applied during recording rather than in post-production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Screen Studio automatically zooms and pans based on cursor activity, smooths and highlights cursor movement and clicks, and applies customizable backgrounds, shadows, and insets to give recordings a polished, presentation-ready look with minimal editing effort.$q$, $q$It also supports webcam, microphone, and system audio capture, iOS screen recording over USB, background noise removal, voice normalization, and locally generated transcripts, with export up to 4K at 60fps, GIF, and shareable hosted links.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79f83550-468f-4378-89d2-b95607e2f72e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The app can be downloaded and used to record and edit for free, but exporting requires a subscription. The annual plan is the best value at roughly 9 USD per month (108 USD per year), while monthly billing has historically run between about 20 and 29 USD per month. A previously offered one-time lifetime license for 229 USD is no longer available to new customers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Simultaneous multi-source recording$q$, $q$Captures screen, webcam, microphone, and system audio at the same time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Multi-track editing timeline$q$, $q$Full non-linear video editor built into the same app used for recording.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Animated callouts and cursor effects$q$, $q$Adds zoom, highlight, and cursor animation effects during editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Built-in transitions, titles, and stock media$q$, $q$Includes transitions, title templates, and access to a royalty-free media library.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$High-quality export and publishing$q$, $q$Exports up to 4K and publishes directly to YouTube and Vimeo.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$iOS device recording$q$, $q$Captures iOS device screens for mobile app tutorials and demos.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Chroma key support$q$, $q$Supports green screen background removal for webcam footage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$One-time perpetual license$q$, $q$Purchased once per major version rather than a mandatory recurring subscription.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$One-time purchase with no mandatory subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Combines recording and a full editing timeline in one app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Mature product with roughly two decades of development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Direct export and publish integrations with YouTube and Vimeo$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Backed by an established video technology company, Telestream$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Mac only, with no native Windows or Linux version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Major version upgrades require a separate paid purchase$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Interface feels dated compared to some newer competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Stock media library is a separate recurring subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Steeper learning curve than single-purpose recorders like Screen Studio$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Is ScreenFlow a one-time purchase or a subscription?$q$, $q$ScreenFlow's base software is a one-time purchase priced at 199 USD; it is not a mandatory recurring subscription, though bundled stock media and support renew annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Does ScreenFlow work on Windows?$q$, $q$No, ScreenFlow is Mac only.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Who makes ScreenFlow?$q$, $q$ScreenFlow is developed by Telestream, an American video technology company founded in 1998 and headquartered in Nevada City, California; the product was originally created by Vara Software, acquired by Telestream in 2008.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Can ScreenFlow edit video, not just record it?$q$, $q$Yes, it includes a full multi-track, non-linear editing timeline alongside its recording features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Do new ScreenFlow versions cost extra?$q$, $q$Yes, major version upgrades typically require a separate paid purchase rather than being free updates.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$What resolution can ScreenFlow export?$q$, $q$ScreenFlow supports export up to 4K resolution, along with MP4, MOV, and animated GIF formats.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$What is the ScreenFlow Super Pak?$q$, $q$It is a bundle, about 275 USD, that includes the base app plus a year of access to a stock media library that renews at 99 USD per year.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Does ScreenFlow support iOS screen recording?$q$, $q$Yes, it can capture iOS device screens for mobile app demos and tutorials.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Online course and tutorial production$q$, $q$Course creators and corporate trainers record and edit lessons entirely within ScreenFlow.$q$, $q$Course creators and corporate trainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$Software demo and product walkthrough videos$q$, $q$IT and documentation teams produce polished walkthroughs of software products for customers or internal training.$q$, $q$SaaS companies and IT documentation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$YouTube and educational content creation$q$, $q$Creators and educators use ScreenFlow's combined capture-and-edit workflow to produce finished videos for publishing.$q$, $q$Content creators and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$ScreenFlow$q$, $q$199 USD$q$, $q$one-time$q$, NULL, $q$["Full screen recording and video editing application","Free trial available before purchase"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$ScreenFlow Super Pak$q$, $q$275 USD (promotional, from 298 USD)$q$, $q$one-time plus annual renewal$q$, NULL, $q$["Base ScreenFlow application","1 year of stock media library access, renews at 99 USD per year"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$ScreenFlow Super Pak Plus$q$, $q$325 USD (promotional, from 357 USD)$q$, $q$one-time plus annual renewal$q$, NULL, $q$["Base ScreenFlow application","Stock media library access","Premium Support, renews at 59 USD per year"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ScreenFlow is Telestream's Mac-only screen recording and video editing application, originally built by Vara Software and first released in 2008 before Telestream acquired the product later that year.$q$, $q$It stands apart from single-purpose screen recorders by pairing capture with a full multi-track editing timeline, letting users finish a video entirely inside one application.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ScreenFlow can simultaneously record the screen, webcam, microphone, and system audio, then lets users edit those tracks on a non-linear timeline with animated callouts, cursor effects, transitions, titles, and chroma key support.$q$, $q$It also includes access to royalty-free stock media, direct export to YouTube and Vimeo, and support for capturing iOS device screens, making it suited to producing finished tutorial and marketing videos rather than raw recordings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45e6cf2f-5a73-4152-bc7c-35947a2f985f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The base ScreenFlow application is a one-time purchase priced at 199 USD, with no mandatory subscription. Telestream also sells bundles: the Super Pak (about 275 USD) adds a year of stock media access that renews at 99 USD per year, and the Super Pak Plus (about 325 USD) adds Premium Support for 59 USD per year on renewal.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Professional page layout and typesetting$q$, $q$Full desktop publishing toolset for laying out newsletters, brochures, books, and magazines.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$CMYK, spot color, and ICC management$q$, $q$Print-oriented color tools including spot color support and ICC color profiles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Print-ready PDF export$q$, $q$Exports versatile PDFs including PDF/X standards suited for prepress workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Advanced typography$q$, $q$Supports footnotes, endnotes, cross-references, and text variables added in version 1.6.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Vector drawing and Symbol/Clone tools$q$, $q$Includes vector drawing tools and an Illustrator-style Symbol and Clone system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Python scripting API$q$, $q$Automates repetitive layout tasks through an extensive Python scripting interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Master pages$q$, $q$Supports reusable master page templates for consistent multi-page documents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Cross-platform availability$q$, $q$Runs natively on Linux, Windows, macOS, BSD, and Haiku.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Completely free with no subscription or license fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Professional-grade print and prepress color management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Active open-source community with regular updates$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Cross-platform, including native Linux support, which is rare among DTP tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Extensible via a Python scripting API$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Steeper learning curve and less polished UI than commercial alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Smaller plugin and extension ecosystem than proprietary competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$No official commercial support or service-level agreement$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Limited file interchange with proprietary InDesign or QuarkXPress files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Slower development pace given its volunteer-driven model$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Is Scribus really free?$q$, $q$Yes, Scribus is free and open-source software released under the GNU General Public License, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Who develops Scribus?$q$, $q$Scribus is developed by a volunteer open-source community; it was originally started in 2001 by German developer Franz Schmid.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$What operating systems does Scribus support?$q$, $q$Scribus runs natively on Linux, Windows, macOS, BSD, and Haiku.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Is Scribus a good alternative to Adobe InDesign?$q$, $q$Scribus offers many professional print-layout features comparable to InDesign, including CMYK, spot color, and PDF/X export, though it has a smaller ecosystem and steeper learning curve.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Can Scribus export print-ready PDFs?$q$, $q$Yes, Scribus supports versatile PDF export including PDF/X standards designed for professional prepress printing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Does Scribus support scripting or automation?$q$, $q$Yes, Scribus includes an extensive Python scripting API for automating layout tasks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$What is the current version of Scribus?$q$, $q$As of 2026 the current stable release series is 1.6.x, with 1.6.6 the latest maintenance release, while a 1.7.x development branch is in progress.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Can Scribus open InDesign or QuarkXPress files?$q$, $q$Scribus has limited support for interchange with proprietary formats like InDesign or QuarkXPress files, and full fidelity is not guaranteed.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Nonprofit and small-business print materials$q$, $q$Organizations produce newsletters, flyers, and brochures without paying for a commercial design subscription.$q$, $q$Nonprofits and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Independent book and magazine layout$q$, $q$Self-published authors and independent publishers lay out books and magazines for print-ready output.$q$, $q$Independent publishers and self-published authors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Educational use for teaching desktop publishing$q$, $q$Schools and training programs use Scribus to teach layout and typesetting concepts without licensing costs.$q$, $q$Students and educators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$Free and Open Source$q$, $q$0$q$, $q$free forever$q$, NULL, $q$["Full desktop publishing feature set","Community support via forums and documentation","Cross-platform availability","Python scripting API"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scribus is a free, open-source desktop publishing application started in 2001 by German developer Franz Schmid to fill a gap in Linux page-layout tools. It is developed by a volunteer community and released under the GNU General Public License.$q$, $q$It is commonly positioned as an open-source alternative to Adobe InDesign or QuarkXPress, built for professional print-ready layout rather than casual document creation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scribus supports CMYK and spot color, ICC color management, and color separations for professional prepress work, alongside versatile PDF export including PDF/X standards. The current 1.6.x stable series adds footnotes, endnotes, cross-references, text variables, and orphan and widow control.$q$, $q$It also includes a Weld tool for joining objects without grouping, a Symbol and Clone facility, master pages, vector drawing tools, and a Python scripting API for automating repetitive layout tasks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scribus is entirely free and open source with no paid tiers, license fees, or subscriptions. It is funded and maintained through volunteer contributions rather than commercial sales, and runs on Linux, Windows, macOS, BSD, and Haiku.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('89f1086c-860a-4405-8ba6-cdbbeb21675a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Infinite zoomable canvas$q$, $q$Provides an unbounded visual workspace for arranging notes and ideas spatially.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Linked cards$q$, $q$Cards hold rich text, images, and embeds and can be freely positioned on the canvas.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Visual connections between notes$q$, $q$Draws explicit relationship lines between related cards to map out thinking.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Real-time collaboration$q$, $q$Multiple users can edit and view the same board simultaneously.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Unlimited boards on paid plans$q$, $q$Removes free-plan caps on cards per board and file uploads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Cross-device sync$q$, $q$Keeps boards synced across devices for continued access.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Community calls and priority support$q$, $q$Pro plan subscribers get access to team community calls and priority support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$File uploads and attachments$q$, $q$Supports uploading files and images directly into cards, with storage limits by plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Intuitive visual and spatial approach to note-taking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Real-time collaboration on shared boards$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Generous free plan for individual light use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Backed by seed funding and under active development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Well suited to research and idea-mapping workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Free plan capped at around 100 cards per board$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Smaller ecosystem and fewer integrations than Notion or Obsidian$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Can become visually cluttered on very large boards$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Primarily web-based, dependent on an internet connection$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Higher effective monthly cost if billed monthly instead of annually$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Is Scrintal free?$q$, $q$Yes, Scrintal has a free plan with unlimited boards capped at about 100 cards per board and 100MB of storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$How much does Scrintal Pro cost?$q$, $q$Scrintal Pro is priced around 9 USD per month when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Who founded Scrintal?$q$, $q$Scrintal was founded in 2020 by Ece Kural and Furkan Bayraktar and is headquartered in Stockholm, Sweden.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Does Scrintal support team collaboration?$q$, $q$Yes, Scrintal supports real-time multi-user collaboration on shared canvases.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$How is Scrintal different from Notion?$q$, $q$Scrintal centers on a visual, spatial canvas with connected cards, while Notion is primarily a linear document and database tool.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Has Scrintal raised funding?$q$, $q$Yes, Scrintal raised a 1 million EUR seed round in January 2023 led by Spintop Ventures with participation from Icebreaker VC.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$What is the difference between the Personal and Pro plans?$q$, $q$The Personal plan removes the free plan's card cap and adds 1GB of storage, while Pro adds unlimited file uploads, real-time collaboration, and priority support.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Is Scrintal available on mobile?$q$, $q$Scrintal is primarily a web-based application accessed through a browser across devices.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Academic and UX research synthesis$q$, $q$Researchers and designers visually cluster interview notes, sources, and findings on connected canvases.$q$, $q$Researchers and UX designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Content and product brainstorming$q$, $q$Teams map out content plans or product ideas visually before committing to a linear document.$q$, $q$Product teams and writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Personal knowledge management$q$, $q$Individuals build a visual, interconnected map of notes and references over time.$q$, $q$Students and individual knowledge workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Free$q$, $q$0$q$, $q$free$q$, NULL, $q$["Unlimited boards","Up to about 100 cards per board","100MB of storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Personal$q$, $q$5 USD per month$q$, $q$annual$q$, NULL, $q$["Unlimited cards per board","1GB of storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$Scrintal Pro$q$, $q$9 USD per month$q$, $q$annual$q$, NULL, $q$["Unlimited docs and boards","Unlimited file uploads","Real-time collaboration","Priority support","Community calls with the team"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scrintal is a Stockholm-based visual note-taking tool, founded in 2020 by Ece Kural and Furkan Bayraktar, that blends an infinite canvas with linked note cards so users can think and organize ideas spatially.$q$, $q$The company raised a 1 million EUR seed round in January 2023 led by Spintop Ventures, with participation from Icebreaker VC, to fund continued development of its visual canvas and collaboration features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users create cards containing rich text, images, and embeds, then arrange and connect them freely on a zoomable canvas to visually map relationships between ideas, sources, and references.$q$, $q$Scrintal supports real-time multi-user collaboration on shared boards, making it suitable for team research, content planning, and product strategy work in addition to individual note-taking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44be1d54-c2e8-47bb-b553-cdc2120d6458', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$A free plan offers unlimited boards capped at about 100 cards per board and 100MB of storage. The Personal plan, around 5 USD per month billed annually, removes the card cap and adds 1GB of storage, while Scrintal Pro, around 9 USD per month billed annually, adds unlimited file uploads, real-time collaboration, and priority support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Legally binding electronic signatures$q$, $q$Provides eIDAS-compliant e-signatures recognized across the European Union.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Nordic and EU eID integration$q$, $q$Integrates with national electronic identification schemes such as BankID and MitID for strong identity verification.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$eSign API$q$, $q$Embeds signing directly into internal software and customer-facing workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Web forms with e-signature$q$, $q$Combines data collection and signature capture in a single form-based flow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Full audit trail$q$, $q$Logs and verifies every step of a signing process for compliance and dispute resolution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$ID Check identity authentication$q$, $q$Verifies signer identity beyond the signature itself.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Multi-country signing support$q$, $q$Supports signing workflows across multiple European countries and languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Managed eSign GO service$q$, $q$Offers an outsourced, managed signing workflow option for businesses that want less setup work.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Strong European eID and eIDAS compliance focus$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Combines e-signature and identity verification in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$High transaction scale reported, over 100 million per year$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Flexible deployment through portal, API, or managed service$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Established company with over a decade in the market$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$No public self-serve pricing, requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Primarily optimized for European and Nordic markets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Onboarding and API integration can require technical work$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Per-transaction cost model can be harder to predict at scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Smaller brand recognition outside Europe compared to global competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$How much does Scrive cost?$q$, $q$Scrive does not publish standard pricing; costs are quote-based after contacting sales, and can include per-transaction and subscription components.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Where is Scrive based?$q$, $q$Scrive is headquartered in Stockholm, Sweden, and was founded in 2010.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Does Scrive support identity verification, not just signatures?$q$, $q$Yes, its eID Hub and ID Check products integrate with national electronic identification schemes such as BankID and MitID to verify signer identity.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Is Scrive legally binding across Europe?$q$, $q$Yes, Scrive's e-signatures are designed to be eIDAS-compliant and legally recognized across the European Union.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Can Scrive be embedded into other software?$q$, $q$Yes, the eSign API allows businesses to embed signing directly into their own applications and workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$How many companies use Scrive?$q$, $q$Scrive states it is used by more than 13,000 companies across over 60 countries.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Does Scrive offer a managed signing service?$q$, $q$Yes, eSign GO offers an outsourced, managed version of the signing workflow.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$What industries commonly use Scrive?$q$, $q$Banks, telecom companies, HR and staffing firms, real estate businesses, and public sector organizations across Europe are common Scrive users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Banking and financial services agreements$q$, $q$Banks and fintechs use Scrive to combine e-signature with strong eID identity verification for regulated agreements.$q$, $q$Banks and fintechs needing eID verification$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$HR and employment contract signing$q$, $q$HR teams and staffing agencies sign employment contracts and onboarding documents digitally with full audit trails.$q$, $q$HR teams and staffing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$Real estate and telecom contract workflows$q$, $q$Real estate, telecom, and public sector organizations process high volumes of signed agreements through Scrive's API and forms.$q$, $q$Real estate, telecom, and public sector organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$eSign Online$q$, $q$Custom pricing$q$, $q$contact sales$q$, NULL, $q$["Self-service signing portal","Full audit trail"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$eSign API$q$, $q$Custom pricing$q$, $q$contact sales, often per-transaction$q$, NULL, $q$["Embed signing directly into internal software and workflows"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$eSign GO$q$, $q$Custom pricing$q$, $q$contact sales$q$, NULL, $q$["Managed, outsourced signing service"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$eID Hub and ID Check$q$, $q$Custom pricing$q$, $q$contact sales$q$, NULL, $q$["Identity verification and authentication add-ons"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scrive is a Stockholm-headquartered e-signature and digital agreement platform founded in 2010, focused primarily on the European market and deeply integrated with Nordic and EU electronic identification systems.$q$, $q$The company is backed by growth equity firm Vitruvian Partners and reports serving more than 13,000 companies across over 60 countries, processing more than 100 million transactions per year.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scrive's product suite spans a self-service signing portal (eSign Online), API and embedded signing tools (eSign API, eSign GO), and identity verification services (eID Hub, ID Check) that connect to national eID schemes such as BankID and MitID.$q$, $q$It also offers Forms Builder and eSign Forms for combining data collection with e-signature capture in a single flow, along with full audit trails needed for regulatory compliance such as GDPR and eIDAS.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('285c3bc6-63b3-46e5-8de1-99baa6d03c1f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scrive does not publish self-serve pricing; each product line, from eSign Online to the API and eID services, routes to a custom quote after a sales conversation. Publicly visible institutional pricing has shown rates around SEK 300 per month per user including 50 transactions, with overage billed per additional transaction.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Continuous control monitoring$q$, $q$Automatically monitors security controls on an ongoing basis rather than only at audit time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Multi-framework compliance mapping$q$, $q$Maps shared controls across SOC 2, ISO 27001, GDPR, HIPAA, and other frameworks to reduce duplicate work.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Cloud infrastructure integrations$q$, $q$Connects to AWS, Azure, and GCP to automate evidence collection for audits.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Risk register and assessments$q$, $q$Tracks organizational risks and supports structured risk assessment processes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Vendor and third-party risk management$q$, $q$Monitors and assesses the security posture of vendors and third parties.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Policy management$q$, $q$Manages and tracks employee acknowledgment of security policies and training.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Audit management workspace$q$, $q$Provides a collaboration space for working with external auditors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Trust page$q$, $q$Offers a public-facing trust or security page to share compliance posture with prospects and customers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Automates evidence collection, reducing manual audit prep$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Supports mapping controls across multiple frameworks at once$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Backed by significant venture funding and active development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Includes vendor risk and policy management beyond certification tracking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Positioned as relatively affordable for early-stage companies versus some larger competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$No public self-serve pricing, requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Can represent a significant annual cost for early-stage startups$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$A separate onboarding fee may apply on top of the subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Smaller brand recognition than category leaders like Vanta or Drata$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Best suited to cloud-native companies, less tailored to on-premise or legacy environments$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$How much does Scrut Automation cost?$q$, $q$Scrut does not publish public pricing; third-party estimates suggest roughly 15,000 to 20,000 USD per year for early-stage companies, scaling up to 40,000 USD or more for enterprise customers with multiple frameworks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Who founded Scrut Automation?$q$, $q$Scrut was founded in August 2021 by Aayush Ghosh Choudhury, Jayesh Gadewar, and Kush Kaushik.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Where is Scrut Automation headquartered?$q$, $q$Scrut is headquartered in Bengaluru, India, with a US office in the Palo Alto and Milpitas, California area.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$What compliance frameworks does Scrut support?$q$, $q$Scrut supports frameworks including SOC 2, ISO 27001, GDPR, and HIPAA, mapping shared controls across multiple frameworks at once.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Does Scrut integrate with cloud infrastructure?$q$, $q$Yes, it connects to AWS, Azure, and GCP, along with HR, identity, and ticketing systems, to automate evidence collection.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$How much funding has Scrut raised?$q$, $q$Scrut has raised about 20.5 million USD in total funding, including a 10 million USD growth round in 2024.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Who are Scrut's main competitors?$q$, $q$Scrut competes with Vanta, Drata, Secureframe, and Sprinto in the compliance automation market.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Does Scrut charge an onboarding fee?$q$, $q$Third-party estimates suggest a one-time onboarding fee of roughly 1,000 to 5,000 USD may apply, though it can be waived on larger contracts.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$SOC 2 and ISO 27001 certification readiness$q$, $q$Startups pursuing their first security certification use Scrut to automate evidence collection and audit prep.$q$, $q$SaaS startups pursuing first-time certification$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Continuous compliance monitoring across frameworks$q$, $q$Growing companies use Scrut to maintain multiple compliance certifications simultaneously through shared control mapping.$q$, $q$Mid-market cloud-native companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Vendor and third-party risk management$q$, $q$Security and GRC teams assess and monitor the risk posture of vendors and partners.$q$, $q$Security and GRC teams at scaling companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Early-stage$q$, $q$Roughly 15,000 to 20,000 USD per year (reported)$q$, $q$annual contract$q$, NULL, $q$["Core compliance automation","Single framework support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Mid-size$q$, $q$Roughly 18,000 to 30,000 USD per year (reported)$q$, $q$annual contract$q$, NULL, $q$["Multi-framework support","Expanded integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$Enterprise$q$, $q$40,000 USD or more per year (reported)$q$, $q$annual contract$q$, NULL, $q$["5 or more compliance frameworks","Dedicated support","Advanced risk management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Scrut Automation is a Bengaluru, India-headquartered GRC platform, founded in August 2021 by Aayush Ghosh Choudhury, Jayesh Gadewar, and Kush Kaushik, that automates security compliance work for growth-stage and cloud-native companies.$q$, $q$The company has raised about 20.5 million USD in total funding and maintains a US office in the Palo Alto and Milpitas, California area alongside its India headquarters.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scrut connects to cloud infrastructure such as AWS, Azure, and GCP, along with HR, identity, and ticketing systems, to continuously monitor security controls and automate evidence collection for audits rather than relying on manual spreadsheets.$q$, $q$The platform includes a risk register, vendor and third-party risk management, policy management, and a framework marketplace that maps shared controls across multiple certifications such as SOC 2, ISO 27001, GDPR, and HIPAA to reduce duplicate audit work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('52bf5267-89af-4200-b109-d8ec448cc105', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Scrut does not publish self-serve pricing; costs are quote-based after a sales conversation. Third-party industry estimates suggest annual contracts of roughly 15,000 to 20,000 USD for early-stage companies, 18,000 to 30,000 USD for mid-size SaaS companies, and 40,000 USD or more for enterprise customers needing multiple frameworks, sometimes with a separate onboarding fee.$q$]::text[], 2);
