-- ── Scribus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source desktop publishing software for professional page layout, typesetting, and print-ready PDF creation, comparable to Adobe InDesign.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Scribus Review 2026: Free Open-Source Desktop Publishing Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Scribus is a free, open-source alternative to InDesign for page layout and print design. See its features, current version, and who it fits best.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scribus is a free and open-source desktop publishing application used for professional page layout, typesetting, and preparing files for commercial printing, often described as an open-source alternative to Adobe InDesign or QuarkXPress. The project was started in 2001 by German developer Franz Schmid, who began writing it to create simple print materials for his in-laws' hotel in Bavaria after finding no adequate free layout tools available for Linux; the first public release, version 0.3, shipped on July 9, 2001. Scribus is written in C++ using the Qt framework and is released under the GNU General Public License, and it is developed by a volunteer open-source community rather than a commercial company, meaning there is no headquarters, employee count, or formal customer support contract; support instead comes through community documentation, mailing lists, and forums. It runs natively on Linux, Windows, macOS, BSD, and Haiku. As of 2026 the current stable release series is 1.6.x, with 1.6.6 the latest maintenance release, following the major 1.6.0 release in January 2024 that added footnotes and endnotes, text variables, cross-references, vertical text justification, and orphan and widow control, plus a Weld feature for joining objects without grouping and a Symbol and Clone tool comparable to Adobe Illustrator's symbol system; a Picture Browser plugin for asset management ships with the app, and a newer 1.7.x development branch is in progress. Core capabilities include CMYK and spot color support, ICC color management for accurate print output, color separations for professional printing, versatile PDF export including PDF/X for prepress, master pages, text frames with advanced typography controls, vector drawing tools, and an extensive Python scripting API for automating repetitive layout tasks. Because it is free, Scribus is popular with independent publishers, nonprofits, small businesses, students, and hobbyists producing newsletters, brochures, magazines, books, and posters who want professional print-ready output without paying for a subscription-based design suite; it is less commonly adopted in large commercial publishing houses that rely on established ecosystems of plugins and collaborative workflow tools built around proprietary software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '89f1086c-860a-4405-8ba6-cdbbeb21675a';

