-- ── Scrintal ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Visual thinking and note-taking tool that combines infinite canvases with connected notes and cards for research, brainstorming, and knowledge mapping.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free plan plus paid subscription tiers)$q$, pricing_model),
  starting_price = COALESCE($q$5 USD per month billed annually (Personal plan)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small team, roughly 1-50 employees$q$, company_size),
  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Scrintal Review 2026: Pricing and Features for Visual Note-Taking$q$, seo_title),
  seo_meta_description = COALESCE($q$Scrintal combines infinite canvases with linked notes for visual thinking and research. See its pricing plans, features, and best use cases in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scrintal is a visual thinking and note-taking application that lets users combine infinite whiteboard-style canvases with linked notes, called cards, to brainstorm, research, and organize ideas visually rather than in a purely linear document. The company was founded in 2020 by Ece Kural and Furkan Bayraktar and is headquartered in Stockholm, Sweden; in January 2023 Scrintal raised a 1 million EUR seed round led by Spintop Ventures with participation from existing investor Icebreaker VC, funding continued development of its visual canvas and collaboration features. The core product lets users create cards containing rich text, images, and embeds, arrange them freely on a zoomable canvas, and draw connections between related cards to build a visual map of their thinking, positioning it as a hybrid between a mind-mapping tool, a whiteboard, and a note-taking app like Notion or Obsidian. Scrintal supports real-time multi-user collaboration on shared boards, making it usable by teams doing collaborative research, content planning, or product strategy work, not just individual note-takers. Pricing follows a freemium model: the free plan includes unlimited mind maps and boards with a cap of around 100 cards per board and 100MB of storage, suitable for individual light use. Paid tiers remove these caps: a Personal plan is priced around 5 USD per month, billed annually, with unlimited cards per board and 1GB of storage, while the Scrintal Pro plan is priced around 9 USD per month, billed annually, and adds unlimited file uploads, real-time collaboration features, priority support, and access to community calls with the Scrintal team. Because pricing is billed annually for the lowest per-month rate, monthly billing where offered costs more per month than the annual commitment. Scrintal is used by researchers, writers, students, UX designers, and product teams who think spatially and want to visually cluster related ideas, references, and sources rather than scrolling through a long linear document; it competes with tools like Heptabase, Milanote, Miro, and Obsidian Canvas in the visual knowledge-management space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '44be1d54-c2e8-47bb-b553-cdc2120d6458';

