  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Swedish$q$]::text[],
  seo_title = COALESCE($q$Scrive Review 2026: Pricing and Features for European E-Signatures$q$, seo_title),
  seo_meta_description = COALESCE($q$Scrive is a Stockholm-based e-signature and eID verification platform for European businesses. See its features, pricing model, and best use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Scrive is a European electronic signature and digital agreement platform founded in Stockholm, Sweden in 2010 by two university friends who initially built the product to simplify signing agreements for international performers touring in Sweden. The company remains headquartered in Stockholm and is backed by growth equity firm Vitruvian Partners; employee counts reported across business databases range from roughly 150 to about 245 people as of late 2025 and 2026. Scrive states it is trusted by more than 13,000 companies across over 60 countries and processes more than 100 million transactions per year, with a strong focus on the European market, including deep integration with Nordic and EU electronic identification schemes such as BankID in Sweden and Norway, MitID in Denmark, and other national eID providers, which differentiates it from more US-centric e-signature tools for organizations that need strong identity verification alongside signatures. The product suite includes eSign Online, a self-service signing portal, eSign GO and eSign API for embedding signing into internal workflows and software, an eID Hub and ID Check for identity verification and authentication, and Forms Builder and eSign Forms for combining data collection with signature capture in a single flow. Scrive does not publish standard self-serve pricing tiers on its website; pricing pages route users to per-product quote requests or a sales conversation, and one publicly visible institutional example, a Swedish university's staff portal, showed a rate of roughly SEK 300 per month per user including 50 signing transactions, with additional transactions billed at about SEK 2 each, though this reflects a negotiated institutional rate rather than list pricing available to all customers. Scrive is commonly adopted by banks, telecom companies, HR and staffing firms, real estate businesses, and public sector organizations across Europe that need legally binding, audit-trailed digital agreements combined with strong identity assurance for regulatory compliance such as GDPR and eIDAS. It competes with DocuSign, Adobe Acrobat Sign, Dropbox Sign, and other eIDAS-compliant regional providers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '285c3bc6-63b3-46e5-8de1-99baa6d03c1f';

